/**
 * Get filtered, paged, and sorted problems with metadata.
 * @param {Object} options
 * @param {string} [options.difficulty] - Filter by difficulty (optional)
 * @param {number} [options.limit=50] - Max number of results to return (max 50)
 * @param {boolean} [options.includeComponents=false] - Whether to include sorted componentLanguages
 * @returns {Object} result with problems array and metadata
 */
function listProblems({ difficulty, limit = 50, includeComponents = false } = {}) {
  // Normalize limit
  const appliedLimit = Math.min(Math.max(parseInt(limit) || 50, 1), 50);

  // Filter by difficulty if provided
  let filteredProblems = problemsData;
  if (difficulty) {
    filteredProblems = filteredProblems.filter(p => p.difficulty === difficulty);
  }

  // Sort by roundId ascending (deterministic ordering)
  filteredProblems.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  // Slice to limit
  const slicedProblems = filteredProblems.slice(0, appliedLimit);

  // Prepare difficulty breakdown for filtered problems
  const difficultyBreakdown = {};
  filteredProblems.forEach(p => {
    difficultyBreakdown[p.difficulty] = (difficultyBreakdown[p.difficulty] || 0) + 1;
  });

  // Map problems for output
  const problems = slicedProblems.map(p => {
    const problem = {
      id: p.id,
      name: p.name,
      difficulty: p.difficulty,
      roundId: p.roundId
    };
    if (includeComponents && Array.isArray(p.componentLanguages)) {
      // Include sorted componentLanguages
      problem.componentLanguages = [...p.componentLanguages].sort();
    }
    return problem;
  });

  return {
    problems,
    totalProblems: problemsData.length,
    filteredCount: filteredProblems.length,
    appliedLimit,
    difficultyBreakdown
  };
}

module.exports = {
  listProblems
};
