/**
 * Controller for GET /api/v1/problems
 * Query params:
 * - difficulty (optional)
 * - limit (optional, max 50)
 * - includeComponents (optional boolean)
 */
async function getProblems(req, res) {
  try {
    const difficulty = req.query.difficulty;
    const limit = req.query.limit;
    const includeComponents = req.query.includeComponents === 'true';

    const result = listProblems({ difficulty, limit, includeComponents });

    res.status(200).json(result);
  } catch (err) {
    res.status(500).json({ error: 'Internal server error' });
  }
}

